package com.example.webviewwrapper

import android.Manifest
import android.app.Activity
import android.content.ContentValues
import android.content.Context
import android.content.SharedPreferences
import android.content.pm.PackageManager
import android.graphics.Bitmap
import android.os.Build
import android.os.Environment
import android.provider.MediaStore
import android.util.Base64
import android.util.Log
import android.webkit.JavascriptInterface
import android.widget.Toast
import androidx.core.app.ActivityCompat
import androidx.core.content.ContextCompat
import org.json.JSONObject
import java.io.ByteArrayOutputStream
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

class NativeBridge(
    private val activity: Activity,
    private val webViewCallback: WebViewCallback
) {
    companion object {
        const val BRIDGE_NAME = "NativeBridge"
        const val TAG = "NativeBridge"
        const val PREFS_NAME = "WebAppLocalStorage"
        const val CAMERA_PERMISSION_REQUEST = 1001
        const val NOTIFICATION_PERMISSION_REQUEST = 1002
    }

    private val sharedPreferences: SharedPreferences =
        activity.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    interface WebViewCallback {
        fun onCameraRequested()
        fun onCameraPermissionGranted()
        fun evaluateJavascript(script: String)
    }

    // ==================== Camera Access ====================

    @JavascriptInterface
    fun requestCameraPermission(): Boolean {
        return if (ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA)
            == PackageManager.PERMISSION_GRANTED
        ) {
            Log.d(TAG, "Camera permission already granted")
            true
        } else {
            activity.runOnUiThread {
                ActivityCompat.requestPermissions(
                    activity,
                    arrayOf(Manifest.permission.CAMERA),
                    CAMERA_PERMISSION_REQUEST
                )
            }
            false
        }
    }

    @JavascriptInterface
    fun hasCameraPermission(): Boolean {
        return ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) ==
                PackageManager.PERMISSION_GRANTED
    }

    @JavascriptInterface
    fun openCamera() {
        if (hasCameraPermission()) {
            activity.runOnUiThread {
                webViewCallback.onCameraRequested()
            }
        } else {
            requestCameraPermission()
        }
    }

    @JavascriptInterface
    fun capturePhoto() {
        openCamera()
    }

    fun onPhotoCaptured(bitmap: Bitmap) {
        val byteArrayOutputStream = ByteArrayOutputStream()
        bitmap.compress(Bitmap.CompressFormat.JPEG, 85, byteArrayOutputStream)
        val byteArray = byteArrayOutputStream.toByteArray()
        val base64Image = Base64.encodeToString(byteArray, Base64.NO_WRAP)

        activity.runOnUiThread {
            webViewCallback.evaluateJavascript(
                "javascript:if(window.onNativePhotoCaptured){window.onNativePhotoCaptured('data:image/jpeg;base64,$base64Image');}"
            )
        }
    }

    fun onPhotoCaptureError(error: String) {
        activity.runOnUiThread {
            webViewCallback.evaluateJavascript(
                "javascript:if(window.onNativePhotoCaptureError){window.onNativePhotoCaptureError('$error');}"
            )
        }
    }

    @JavascriptInterface
    fun savePhotoToGallery(base64Data: String): Boolean {
        return try {
            val imageData = base64Data.replace("data:image/jpeg;base64,", "")
                .replace("data:image/png;base64,", "")
            val decodedBytes = Base64.decode(imageData, Base64.DEFAULT)
            val bitmap = android.graphics.BitmapFactory.decodeByteArray(decodedBytes, 0, decodedBytes.size)

            val timestamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.getDefault()).format(Date())
            val fileName = "IMG_$timestamp.jpg"

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
                val contentValues = ContentValues().apply {
                    put(MediaStore.MediaColumns.DISPLAY_NAME, fileName)
                    put(MediaStore.MediaColumns.MIME_TYPE, "image/jpeg")
                    put(MediaStore.MediaColumns.RELATIVE_PATH, Environment.DIRECTORY_PICTURES)
                }
                val uri = activity.contentResolver.insert(
                    MediaStore.Images.Media.EXTERNAL_CONTENT_URI, contentValues
                )
                uri?.let {
                    activity.contentResolver.openOutputStream(it)?.use { outputStream ->
                        bitmap.compress(Bitmap.CompressFormat.JPEG, 90, outputStream)
                    }
                }
            }

            activity.runOnUiThread {
                Toast.makeText(activity, "Photo saved to gallery", Toast.LENGTH_SHORT).show()
            }
            true
        } catch (e: Exception) {
            Log.e(TAG, "Error saving photo: ${e.message}")
            false
        }
    }

    // ==================== Local Storage ====================

    @JavascriptInterface
    fun setItem(key: String, value: String) {
        sharedPreferences.edit().putString(key, value).apply()
        Log.d(TAG, "Stored: $key = $value")
    }

    @JavascriptInterface
    fun getItem(key: String): String? {
        val value = sharedPreferences.getString(key, null)
        Log.d(TAG, "Retrieved: $key = $value")
        return value
    }

    @JavascriptInterface
    fun removeItem(key: String) {
        sharedPreferences.edit().remove(key).apply()
        Log.d(TAG, "Removed: $key")
    }

    @JavascriptInterface
    fun clear() {
        sharedPreferences.edit().clear().apply()
        Log.d(TAG, "Storage cleared")
    }

    @JavascriptInterface
    fun getAllKeys(): String {
        val keys = sharedPreferences.all.keys.toList()
        return org.json.JSONArray(keys).toString()
    }

    @JavascriptInterface
    fun getAll(): String {
        val allEntries = sharedPreferences.all
        val jsonObject = JSONObject()
        for ((key, value) in allEntries) {
            jsonObject.put(key, value.toString())
        }
        return jsonObject.toString()
    }

    @JavascriptInterface
    fun setSecureItem(key: String, value: String) {
        val encoded = Base64.encodeToString(value.toByteArray(), Base64.DEFAULT)
        sharedPreferences.edit().putString("secure_$key", encoded).apply()
    }

    @JavascriptInterface
    fun getSecureItem(key: String): String? {
        val encoded = sharedPreferences.getString("secure_$key", null) ?: return null
        return String(Base64.decode(encoded, Base64.DEFAULT))
    }

    // ==================== Push Notifications ====================

    @JavascriptInterface
    fun requestNotificationPermission(): Boolean {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (ContextCompat.checkSelfPermission(
                    activity, Manifest.permission.POST_NOTIFICATIONS
                ) == PackageManager.PERMISSION_GRANTED
            ) {
                true
            } else {
                activity.runOnUiThread {
                    ActivityCompat.requestPermissions(
                        activity,
                        arrayOf(Manifest.permission.POST_NOTIFICATIONS),
                        NOTIFICATION_PERMISSION_REQUEST
                    )
                }
                false
            }
        } else {
            true
        }
    }

    @JavascriptInterface
    fun hasNotificationPermission(): Boolean {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            ContextCompat.checkSelfPermission(
                activity, Manifest.permission.POST_NOTIFICATIONS
            ) == PackageManager.PERMISSION_GRANTED
        } else {
            true
        }
    }

    @JavascriptInterface
    fun getFCMToken(): String? {
        return sharedPreferences.getString("fcm_token", null)
    }

    @JavascriptInterface
    fun subscribeToPushTopic(topic: String) {
        try {
            com.google.firebase.messaging.FirebaseMessaging.getInstance()
                .subscribeToTopic(topic)
                .addOnCompleteListener { task ->
                    val result = if (task.isSuccessful) "success" else "failed"
                    Log.d(TAG, "Subscribe to $topic: $result")
                    activity.runOnUiThread {
                        webViewCallback.evaluateJavascript(
                            "javascript:if(window.onPushTopicSubscribed){window.onPushTopicSubscribed('$topic','$result');}"
                        )
                    }
                }
        } catch (e: Exception) {
            Log.e(TAG, "Firebase not initialized: ${e.message}")
        }
    }

    @JavascriptInterface
    fun unsubscribeFromPushTopic(topic: String) {
        try {
            com.google.firebase.messaging.FirebaseMessaging.getInstance()
                .unsubscribeFromTopic(topic)
                .addOnCompleteListener { task ->
                    val result = if (task.isSuccessful) "success" else "failed"
                    Log.d(TAG, "Unsubscribe from $topic: $result")
                    activity.runOnUiThread {
                        webViewCallback.evaluateJavascript(
                            "javascript:if(window.onPushTopicUnsubscribed){window.onPushTopicUnsubscribed('$topic','$result');}"
                        )
                    }
                }
        } catch (e: Exception) {
            Log.e(TAG, "Firebase not initialized: ${e.message}")
        }
    }

    fun saveFCMToken(token: String) {
        sharedPreferences.edit().putString("fcm_token", token).apply()
        activity.runOnUiThread {
            webViewCallback.evaluateJavascript(
                "javascript:if(window.onFCMTokenReceived){window.onFCMTokenReceived('$token');}"
            )
        }
    }

    fun onPushNotificationReceived(title: String, body: String, data: String) {
        activity.runOnUiThread {
            val escapedTitle = title.replace("'", "\\'")
            val escapedBody = body.replace("'", "\\'")
            val escapedData = data.replace("'", "\\'")
            webViewCallback.evaluateJavascript(
                "javascript:if(window.onPushNotificationReceived){window.onPushNotificationReceived('$escapedTitle','$escapedBody','$escapedData');}"
            )
        }
    }

    // ==================== Device Info ====================

    @JavascriptInterface
    fun getDeviceInfo(): String {
        val json = JSONObject()
        json.put("manufacturer", Build.MANUFACTURER)
        json.put("model", Build.MODEL)
        json.put("osVersion", Build.VERSION.RELEASE)
        json.put("sdkVersion", Build.VERSION.SDK_INT)
        json.put("platform", "android")
        json.put("appVersion", getAppVersion())
        return json.toString()
    }

    @JavascriptInterface
    fun getAppVersion(): String {
        return try {
            val packageInfo = activity.packageManager.getPackageInfo(activity.packageName, 0)
            packageInfo.versionName ?: "unknown"
        } catch (e: Exception) {
            "unknown"
        }
    }

    @JavascriptInterface
    fun getPlatform(): String = "android"

    // ==================== Utility ====================

    @JavascriptInterface
    fun showToast(message: String) {
        activity.runOnUiThread {
            Toast.makeText(activity, message, Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun showLongToast(message: String) {
        activity.runOnUiThread {
            Toast.makeText(activity, message, Toast.LENGTH_LONG).show()
        }
    }

    @JavascriptInterface
    fun log(tag: String, message: String) {
        Log.d(tag, message)
    }

    @JavascriptInterface
    fun shareText(text: String, title: String) {
        val sendIntent = android.content.Intent().apply {
            action = android.content.Intent.ACTION_SEND
            putExtra(android.content.Intent.EXTRA_TEXT, text)
            type = "text/plain"
        }
        val shareIntent = android.content.Intent.createChooser(sendIntent, title)
        activity.startActivity(shareIntent)
    }

    @JavascriptInterface
    fun vibrate(milliseconds: Long) {
        val vibrator = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
            val vibratorManager = activity.getSystemService(Context.VIBRATOR_MANAGER_SERVICE) as android.os.VibratorManager
            vibratorManager.defaultVibrator
        } else {
            @Suppress("DEPRECATION")
            activity.getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
        }
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            vibrator.vibrate(android.os.VibrationEffect.createOneShot(milliseconds, android.os.VibrationEffect.DEFAULT_AMPLITUDE))
        } else {
            @Suppress("DEPRECATION")
            vibrator.vibrate(milliseconds)
        }
    }

    @JavascriptInterface
    fun copyToClipboard(text: String) {
        activity.runOnUiThread {
            val clipboard = activity.getSystemService(Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
            val clip = android.content.ClipData.newPlainText("Copied Text", text)
            clipboard.setPrimaryClip(clip)
            Toast.makeText(activity, "Copied to clipboard", Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun openExternalUrl(url: String) {
        val intent = android.content.Intent(android.content.Intent.ACTION_VIEW, android.net.Uri.parse(url))
        activity.startActivity(intent)
    }
}


